snapshot.eval/tests/unit/tree-edit/add-relationsh:
{
  "input": {
    "scenario": "mid-research-flynn",
    "user_message": "The parentage proof ps_001 is at `probable` tier. Make sure tree.gedcomx.json reflects the ParentChild relationship between Thomas and Patrick."
  },
  "judge_context": [
    "Should confirm R1 (Thomas I2 → Patrick I1, type ParentChild) already exists in tree.gedcomx.json — it was created when ps_001 reached `probable`, per the proof-conclusion timing rule",
    "Should verify R1's sources list reflects the supporting evidence chain from the underlying proof summary",
    "Should make NO modifications if R1 is already in place and correctly sourced — edit-minimality is the right behavior. If sources are missing, ADD them but don't churn other fields",
    "Should NOT delete R1 even if the proof tier were lowered later — tree edits to remove relationships require explicit re-evaluation, not automatic syncing with proof tier"
  ],
  "test": {
    "id": "ut_tree_edit_002",
    "skill": "tree-edit",
    "type": "positive"
  }
}

snapshot.eval/tests/unit/tree-edit/negative-recor:
{
  "input": {
    "scenario": "mid-research-flynn",
    "user_message": "I just found the 1880 census for Patrick Flynn. Add the facts from that record to the tree."
  },
  "judge_context": [
    "Should route to record-extraction rather than write 1880 census facts directly to tree.gedcomx.json"
  ],
  "negative": {
    "correct_skill": [
      "record-extraction"
    ],
    "explanation": "Facts from a newly-found record should be extracted as assertions in research.json (record-extraction's job), not written directly to tree.gedcomx.json. The tree is updated via proof-conclusion once an assertion is part of a `probable`-tier conclusion — not directly from extraction. Skipping that path would put unverified facts into the deliverable file."
  },
  "test": {
    "id": "ut_tree_edit_003",
    "skill": "tree-edit",
    "type": "negative"
  }
}

